section.programlisting:
scenario("hello-netty-udp-world") {
        minionsCount = 100
        rampUp {
            // Starts all at once.
            regular(100, minionsCount)
        }
    }
    .start()
    .netty()

    .tcp { 
        name = "my-tcp"
        connect {
            address("localhost", availableTcpPort)
            noDelay = true
        }
        request { tcpRequest1 }
        metrics { connectTime = true }
        events { connection = true }
    }

    .reuseTcp("my-tcp") { 
        name = "reuse-tcp"
        iterate(20, Duration.ofMillis(100))
        request { tcpRequest2 }
    }

reuseTcp("my-tcp") {
    request { tcpRequest2 }
}.configure {
    name = "reuse-tcp" 
    iterate(20, Duration.ofMillis(100)) 
    retryPolicy(instanceOfRetryPolicy) 
    timeout(2000) 
}

execute { } 
    .innerJoin<EntityWithKey, EntityWithId>(
        on = { "${it.key}" }, 
        with = "my-datasource-poll-step", 
        having = { it.id } 
    )
    .map { }

execute { }
    .innerJoin<EntityWithKey, EntityWithId>(
        on = { "${it.key}" },
        with = { 
            r2dbc().poll{
                // ...
            }
        },
        having = { it.id }
    )
    .map {}

stage("my-stage") {
    map { it * 3 }.map { arrayOf(it, it + 100) }.flatten() 
}.configure { 
    iterate(5)
}
